class Solution:
    def maxKDistinct(self, nums, k):
        distinct = []
        for v in nums:
            if v not in distinct:
                distinct.append(v)
        for i in range(len(distinct)):
            for j in range(i + 1, len(distinct)):
                if distinct[j] > distinct[i]:
                    distinct[i], distinct[j] = distinct[j], distinct[i]
        return distinct[:k]

